CREATE TABLE IF NOT EXISTS product_bundles (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, slug TEXT NOT NULL, title TEXT NOT NULL, description TEXT NOT NULL DEFAULT '', image_url TEXT NOT NULL DEFAULT '', pricing_mode TEXT NOT NULL DEFAULT 'sum', fixed_price_cents INTEGER NOT NULL DEFAULT 0, discount_bps INTEGER NOT NULL DEFAULT 0, status TEXT NOT NULL DEFAULT 'draft', created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, UNIQUE (merchant_id, slug));
CREATE TABLE IF NOT EXISTS product_bundle_items (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, bundle_id TEXT NOT NULL, product_id TEXT NOT NULL, variant_id TEXT NOT NULL DEFAULT '', quantity INTEGER NOT NULL DEFAULT 1, required INTEGER NOT NULL DEFAULT 1, position INTEGER NOT NULL DEFAULT 0, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (bundle_id) REFERENCES product_bundles(id) ON DELETE CASCADE, FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS suppliers (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, name TEXT NOT NULL, contact_name TEXT NOT NULL DEFAULT '', email TEXT NOT NULL DEFAULT '', phone TEXT NOT NULL DEFAULT '', website TEXT NOT NULL DEFAULT '', country_code TEXT NOT NULL DEFAULT 'US', lead_time_days INTEGER NOT NULL DEFAULT 0, minimum_order_cents INTEGER NOT NULL DEFAULT 0, active INTEGER NOT NULL DEFAULT 1, notes TEXT NOT NULL DEFAULT '', created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS purchase_orders (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, supplier_id TEXT, location_id TEXT, status TEXT NOT NULL DEFAULT 'draft', expected_at TEXT NOT NULL DEFAULT '', received_at TEXT, currency TEXT NOT NULL DEFAULT 'USD', total_cost_cents INTEGER NOT NULL DEFAULT 0, notes TEXT NOT NULL DEFAULT '', created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (supplier_id) REFERENCES suppliers(id) ON DELETE SET NULL, FOREIGN KEY (location_id) REFERENCES inventory_locations(id) ON DELETE SET NULL);
CREATE TABLE IF NOT EXISTS purchase_order_items (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, purchase_order_id TEXT NOT NULL, product_id TEXT NOT NULL DEFAULT '', variant_id TEXT NOT NULL DEFAULT '', sku TEXT NOT NULL DEFAULT '', title TEXT NOT NULL DEFAULT '', quantity INTEGER NOT NULL DEFAULT 1, received_quantity INTEGER NOT NULL DEFAULT 0, unit_cost_cents INTEGER NOT NULL DEFAULT 0, line_total_cents INTEGER NOT NULL DEFAULT 0, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (purchase_order_id) REFERENCES purchase_orders(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS customer_segments (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, name TEXT NOT NULL, segment_key TEXT NOT NULL, rules_json TEXT NOT NULL DEFAULT '{}', active INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, UNIQUE (merchant_id, segment_key));
CREATE TABLE IF NOT EXISTS price_lists (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, name TEXT NOT NULL, segment_id TEXT, currency TEXT NOT NULL DEFAULT 'USD', active INTEGER NOT NULL DEFAULT 1, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (segment_id) REFERENCES customer_segments(id) ON DELETE SET NULL);
CREATE TABLE IF NOT EXISTS price_list_items (id TEXT PRIMARY KEY, merchant_id TEXT NOT NULL, price_list_id TEXT NOT NULL, product_id TEXT NOT NULL DEFAULT '', variant_id TEXT NOT NULL DEFAULT '', adjustment_type TEXT NOT NULL DEFAULT 'percent', adjustment_bps INTEGER NOT NULL DEFAULT 0, price_cents INTEGER NOT NULL DEFAULT 0, created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (merchant_id) REFERENCES merchants(id) ON DELETE CASCADE, FOREIGN KEY (price_list_id) REFERENCES price_lists(id) ON DELETE CASCADE);
CREATE INDEX IF NOT EXISTS idx_product_bundles_merchant ON product_bundles (merchant_id, status, updated_at DESC);
CREATE INDEX IF NOT EXISTS idx_product_bundle_items_bundle ON product_bundle_items (bundle_id, position ASC);
CREATE INDEX IF NOT EXISTS idx_suppliers_merchant ON suppliers (merchant_id, active, updated_at DESC);
CREATE INDEX IF NOT EXISTS idx_purchase_orders_merchant ON purchase_orders (merchant_id, status, updated_at DESC);
CREATE INDEX IF NOT EXISTS idx_purchase_order_items_order ON purchase_order_items (purchase_order_id, created_at ASC);
CREATE INDEX IF NOT EXISTS idx_customer_segments_merchant ON customer_segments (merchant_id, active, updated_at DESC);
CREATE INDEX IF NOT EXISTS idx_price_lists_merchant ON price_lists (merchant_id, active, updated_at DESC);
CREATE INDEX IF NOT EXISTS idx_price_list_items_list ON price_list_items (price_list_id, created_at ASC);
